package com.pqc.core.entity;
import jakarta.persistence.*; import lombok.*; import java.math.BigDecimal; import java.time.LocalDateTime;
@Entity @Table(name="offers") @Data @Builder @NoArgsConstructor @AllArgsConstructor public class Offer {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false,unique=true) private String code; @Column(nullable=false) private String title; @Column(length=2000) private String description; @Enumerated(EnumType.STRING) @Column(nullable=false) private DiscountType discountType; @Column(nullable=false) private BigDecimal discountValue; @Column(nullable=false) private BigDecimal minOrderAmount; private BigDecimal maxDiscountAmount; private Integer usageLimit; @Builder.Default @Column(nullable=false) private int usedCount=0; @Enumerated(EnumType.STRING) private Role targetRole; @Builder.Default @Column(nullable=false) private boolean active=true; @Column(nullable=false) private LocalDateTime startsAt; @Column(nullable=false) private LocalDateTime endsAt; private LocalDateTime createdAt; private LocalDateTime updatedAt; @PrePersist void create(){createdAt=updatedAt=LocalDateTime.now();} @PreUpdate void update(){updatedAt=LocalDateTime.now();}}
